-- ============================================================================
-- BADRAN IMPORT v4 (draft, review before execution)
-- Source of truth: supabase/scripts/bulk-upload-4-badran.json
-- Strategy:
--   1) Preserve the original mini tree in DEV.
--   2) Keep existing bridge node 083 (عبد الحليم).
--   3) Remove the old bulk-upload-3 addon around that bridge.
--   4) Insert the new extracted incoming tree in a fresh 2000... namespace.
--   5) Reconnect the incoming tree to the preserved bridge node only.
-- ============================================================================

-- Existing bridge UUID kept intact: 10000000-1000-4000-8000-000000000083
-- Old addon rows removed first: 334 nodes, 321 links
-- New v4 rows inserted: 454 nodes, 447 internal links, 1 bridge link(s)
-- Protected source subtree root omitted from v4 insert: 131 (size 223 source nodes)

-- ============================================================================
-- STEP 1: Remove the old bulk-upload-3 addon from DEV, but keep node 083
-- ============================================================================

-- Remove the incorrect old bridge link (00b is Aysha in the mini tree, not بدوي)
DELETE FROM public.links
WHERE source_node_id = '10000000-1000-4000-8000-00000000000b'
  AND target_node_id = '10000000-1000-4000-8000-000000000083'
  AND type = 'parent';

-- Remove links touching the old addon nodes being replaced
DELETE FROM public.links
WHERE source_node_id::text >= '10000000-1000-4000-8000-00000000004b'
  AND source_node_id::text <= '10000000-1000-4000-8000-0000000001a2'
  AND source_node_id::text <> '10000000-1000-4000-8000-000000000083';

DELETE FROM public.links
WHERE target_node_id::text >= '10000000-1000-4000-8000-00000000004b'
  AND target_node_id::text <= '10000000-1000-4000-8000-0000000001a2'
  AND target_node_id::text <> '10000000-1000-4000-8000-000000000083';

-- Remove old addon nodes being replaced
DELETE FROM public.nodes
WHERE id::text >= '10000000-1000-4000-8000-00000000004b'
  AND id::text <= '10000000-1000-4000-8000-0000000001a2'
  AND id::text <> '10000000-1000-4000-8000-000000000083';

-- ============================================================================
-- STEP 2: Insert the new v4 extracted tree in a fresh namespace
-- ============================================================================

ON CONFLICT (id) DO NOTHING;

;

-- Correct bridge: new بدوي node -> preserved existing عبد الحليم node 083
;

-- Verification helpers
SELECT COUNT(*) AS inserted_v4_nodes FROM public.nodes WHERE id::text LIKE '20000000-1000-4000-8000-%';
SELECT COUNT(*) AS inserted_v4_links FROM public.links WHERE source_node_id::text LIKE '20000000-1000-4000-8000-%' OR target_node_id::text LIKE '20000000-1000-4000-8000-%';
SELECT id::text, name FROM public.nodes WHERE id = '10000000-1000-4000-8000-000000000083'::uuid;
